#include <iostream>
#include <cmath>

using namespace std;

void generatePattern(int size) {
    for (int i = 0; i < size; ++i) {
        for (int k = 0; k < size; ++k) {
            int val = (i * k) + (i + k) + (i ^ k);
            cout << val << " ";
        }
        cout << endl;
    }
}

int main() {
    int size;
    cout << "Enter the size of the pattern: ";
    cin >> size;

    generatePattern(size);
    return 0;
}
